`timescale 1ns/1ps
// node_conv_222 — pointwise (1x1) conv2d, tiled-streaming contract.
//   IC=128, OC=512, IH=IW=28, OH=OW=28 (stride 1, padding 0).
//   MP=4, channel_tile=32 -> IN_BEATS=4, OUT_BEATS=16.
//   Latency = IN_BEATS + OC_PASSES * (MP*K_TOTAL + 6)
//           = 4 + 128 * (4*128 + 6) = 4 + 128*518 = 66308.

module node_conv_222 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);

    localparam integer IC = 128;
    localparam integer OC = 512;
    localparam integer OH = 28;
    localparam integer OW = 28;
    localparam integer KH = 1;
    localparam integer KW = 1;
    localparam integer K_TOTAL = IC*KH*KW;
    localparam integer MP = 4;
    localparam integer OC_PASSES    = (OC + MP - 1) / MP;
    localparam integer CHANNEL_TILE = 32;
    localparam integer IN_BEATS     = (IC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam integer OUT_BEATS    = (OC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam integer TILE_BITS    = CHANNEL_TILE * 8;
    localparam integer SCALE_MULT  = 2796;
    localparam integer SCALE_SHIFT = 19;
    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = PROD_W + $clog2(K_TOTAL);
    localparam integer BIAS_W        = 32;
    localparam integer BIASED_W      = ((ACC_W > BIAS_W) ? ACC_W : BIAS_W) + 1;
    localparam integer SCALE_MAG_W   = $clog2(SCALE_MULT + 1);
    localparam integer SCALE_CONST_W = SCALE_MAG_W + 1;
    localparam integer SCALED_W      = BIASED_W + SCALE_CONST_W;
    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 =
        SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};
    (* rom_style = "block", ram_style = "block" *)
    reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *)
    reg signed [31:0] biases  [0:OC-1];
    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_222_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_222_bias.hex",    biases);
    end
    reg [IC*8-1:0] in_latch_flat;
    reg [OC*8-1:0] out_pack;
    localparam [2:0] ST_LOAD=3'd0, ST_RUNNING=3'd1, ST_BIAS=3'd2, ST_SCALE=3'd3, ST_OUTPUT=3'd4, ST_EMIT=3'd5;
    reg [2:0] state;
    reg [1:0]  in_beat_idx;
    reg [3:0]  out_beat_idx;
    reg [9:0]  pixel_count;
    reg [6:0]  oc_group;
    reg [1:0]  lane_counter;
    reg [6:0]  k_counter;
    reg signed [ACC_W-1:0]    acc    [0:MP-1];
    reg signed [BIASED_W-1:0] biased [0:MP-1];
    reg signed [SCALED_W-1:0] scaled [0:MP-1];
    reg signed [SCALED_W-1:0] v_tmp;
    reg signed [7:0]            weight_q;
    reg signed [7:0]            act_q;
    (* use_dsp = "yes" *)
    reg signed [PROD_W-1:0]     mul_q;
    reg                         mac_valid_q1, mac_valid_q2;
    reg [1:0]                   mac_lane_q1,  mac_lane_q2;
    reg                         mac_done_issuing;
    reg [1:0]                   mac_drain;
    integer i, lane, global_oc;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            ready_in<=1'b1; valid_out<=1'b0; data_out<=256'd0; state<=ST_LOAD;
            in_beat_idx<=0; out_beat_idx<=0; pixel_count<=0;
            oc_group<=0; lane_counter<=0; k_counter<=0;
            weight_q<=0; act_q<=0; mul_q<=0;
            mac_valid_q1<=0; mac_valid_q2<=0; mac_lane_q1<=0; mac_lane_q2<=0;
            mac_done_issuing<=0; mac_drain<=0;
            in_latch_flat<=0; out_pack<=0;
            for (i=0;i<MP;i=i+1) begin acc[i]<=0; biased[i]<=0; scaled[i]<=0; end
        end else begin
            valid_out<=1'b0; mac_valid_q1<=1'b0;
            mul_q<=weight_q*act_q; mac_valid_q2<=mac_valid_q1; mac_lane_q2<=mac_lane_q1;
            if (mac_valid_q2) acc[mac_lane_q2]<=acc[mac_lane_q2]+mul_q;
            case (state)
                ST_LOAD: if (valid_in&&ready_in) begin
                    in_latch_flat[in_beat_idx*TILE_BITS +: TILE_BITS]<=data_in;
                    if (in_beat_idx==IN_BEATS-1) begin
                        in_beat_idx<=0; ready_in<=1'b0;
                        oc_group<=0; lane_counter<=0; k_counter<=0;
                        mac_done_issuing<=0; mac_drain<=0;
                        for (i=0;i<MP;i=i+1) acc[i]<=0;
                        state<=ST_RUNNING;
                    end else in_beat_idx<=in_beat_idx+1'b1;
                end
                ST_RUNNING: if (!mac_done_issuing) begin
                    weight_q<=weights[(oc_group*MP+lane_counter)*K_TOTAL+k_counter];
                    act_q<=$signed(in_latch_flat[k_counter*8 +: 8]);
                    mac_valid_q1<=1'b1; mac_lane_q1<=lane_counter;
                    if (k_counter==K_TOTAL-1) begin
                        k_counter<=0;
                        if (lane_counter==MP-1) begin lane_counter<=0; mac_done_issuing<=1'b1; mac_drain<=0; end
                        else lane_counter<=lane_counter+1'b1;
                    end else k_counter<=k_counter+1'b1;
                end else begin
                    if (mac_drain==2'd2) state<=ST_BIAS; else mac_drain<=mac_drain+1'b1;
                end
                ST_BIAS: begin
                    for (lane=0;lane<MP;lane=lane+1) biased[lane]<=acc[lane]+biases[oc_group*MP+lane];
                    state<=ST_SCALE;
                end
                ST_SCALE: begin
                    for (lane=0;lane<MP;lane=lane+1) scaled[lane]<=biased[lane]*SCALE_MULT_CONST;
                    state<=ST_OUTPUT;
                end
                ST_OUTPUT: begin
                    for (lane=0;lane<MP;lane=lane+1) begin
                        global_oc=oc_group*MP+lane;
                        v_tmp=(scaled[lane]+(scaled[lane][SCALED_W-1]?SCALE_ROUND_HALF_M1:SCALE_ROUND_HALF))>>>SCALE_SHIFT;
                        out_pack[global_oc*8 +: 8]<=(v_tmp>127)?8'sd127:(v_tmp<-128)?-8'sd128:v_tmp[7:0];
                    end
                    if (oc_group==OC_PASSES-1) begin
                        valid_out<=1'b1; data_out<=out_pack[0 +: TILE_BITS];
                        out_beat_idx<=4'd1; oc_group<=0; state<=ST_EMIT;
                    end else begin
                        oc_group<=oc_group+1'b1; lane_counter<=0; k_counter<=0;
                        mac_done_issuing<=0; mac_drain<=0;
                        for (i=0;i<MP;i=i+1) acc[i]<=0;
                        state<=ST_RUNNING;
                    end
                end
                ST_EMIT: begin
                    valid_out<=1'b1; data_out<=out_pack[out_beat_idx*TILE_BITS +: TILE_BITS];
                    if (out_beat_idx==OUT_BEATS-1) begin
                        out_beat_idx<=0; ready_in<=1'b1;
                        if (pixel_count==OH*OW-1) pixel_count<=0; else pixel_count<=pixel_count+1'b1;
                        state<=ST_LOAD;
                    end else out_beat_idx<=out_beat_idx+1'b1;
                end
                default: state<=ST_LOAD;
            endcase
        end
    end
endmodule
